int main()
{
	int n,t;
	scanf("%d %d",&n,&t);
	char s[n];
	scanf("%s",s);
	int l=strlen(s),i,j;
	for (i=0; i<t; i++)
		for (j=l-2; j>=0; j--)
			if (s[j]=='B' && s[j+1]=='G')
			{
				s[j]='G';
				s[j+1]='B';
				j--;
			}
